from dataclasses import dataclass
from typing import List

@dataclass
class Record:
    field1: int
    field2: str
    field3: float

def initialize_records() -> List[Record]:
    records = [
        Record(field1=1, field2='A', field3=10.0),
        Record(field1=2, field2='B', field3=20.0),
        Record(field1=3, field2='C', field3=30.0)
    ]
    return records

def process_records(records: List[Record]) -> None:
    for record in records:
        if record.field1 % 2 == 0:
            record.field3 *= 1.1
        else:
            record.field3 *= 0.9

def display_records(records: List[Record]) -> None:
    for record in records:
        print(f"{record.field1}{record.field2}{record.field3:.2f}")

def main() -> None:
    records = initialize_records()
    process_records(records)
    display_records(records)

if __name__ == "__main__":
    main()
